<template>
  <div class="mini-map" ref="miniMap">
    <div class="mini-map-header">
      <span>小地图</span>
      <button class="close-btn" @click="$emit('close')">×</button>
    </div>
    <div class="mini-map-content">
      <div class="map-container" ref="mapContainer">
        <div 
          class="map-canvas" 
          ref="mapCanvas"
          @mousedown="handleMapMouseDown"
          @mousemove="handleMapMouseMove"
          @mouseup="handleMapMouseUp"
          @mouseleave="handleMapMouseUp"
        >
          <div 
            class="viewport-rect" 
            ref="viewportRect"
            :style="viewportStyle"
            @mousedown="handleViewportMouseDown"
            @mousemove="handleViewportMouseMove"
            @mouseup="handleViewportMouseUp"
            @mouseleave="handleViewportMouseUp"
          ></div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'MiniMap',
  props: {
    stageWidth: {
      type: Number,
      default: 800
    },
    stageHeight: {
      type: Number,
      default: 600
    },
    viewportPosition: {
      type: Object,
      default: () => ({ x: 0, y: 0 })
    },
    scale: {
      type: Number,
      default: 1
    }
  },
  data() {
    return {
      isDraggingMap: false,
      isDraggingViewport: false,
      lastMousePos: { x: 0, y: 0 }
    }
  },
  computed: {
    viewportStyle() {
      const scale = this.mapScale
      const viewportWidth = this.stageWidth * scale * (1 / this.scale)
      const viewportHeight = this.stageHeight * scale * (1 / this.scale)
      const viewportX = (this.viewportPosition.x * scale) * -1
      const viewportY = (this.viewportPosition.y * scale) * -1
      
      return {
        width: `${viewportWidth}px`,
        height: `${viewportHeight}px`,
        left: `${viewportX}px`,
        top: `${viewportY}px`
      }
    },
    mapScale() {
      const mapWidth = 200
      const mapHeight = 150
      const scaleX = mapWidth / this.stageWidth
      const scaleY = mapHeight / this.stageHeight
      return Math.min(scaleX, scaleY) * 0.8
    }
  },
  methods: {
    handleMapMouseDown(e) {
      this.isDraggingMap = true
      this.lastMousePos = this.getMousePos(e)
    },
    handleMapMouseMove(e) {
      if (!this.isDraggingMap) return
      
      const currentPos = this.getMousePos(e)
      const deltaX = (currentPos.x - this.lastMousePos.x) / this.mapScale
      const deltaY = (currentPos.y - this.lastMousePos.y) / this.mapScale
      
      this.$emit('viewport-change', {
        x: this.viewportPosition.x - deltaX * this.scale,
        y: this.viewportPosition.y - deltaY * this.scale
      })
      
      this.lastMousePos = currentPos
    },
    handleMapMouseUp() {
      this.isDraggingMap = false
    },
    handleViewportMouseDown(e) {
      e.stopPropagation()
      this.isDraggingViewport = true
      this.lastMousePos = this.getMousePos(e)
    },
    handleViewportMouseMove(e) {
      if (!this.isDraggingViewport) return
      e.stopPropagation()
      
      const currentPos = this.getMousePos(e)
      const deltaX = (currentPos.x - this.lastMousePos.x) / this.mapScale
      const deltaY = (currentPos.y - this.lastMousePos.y) / this.mapScale
      
      this.$emit('viewport-change', {
        x: this.viewportPosition.x - deltaX * this.scale,
        y: this.viewportPosition.y - deltaY * this.scale
      })
      
      this.lastMousePos = currentPos
    },
    handleViewportMouseUp() {
      this.isDraggingViewport = false
    },
    getMousePos(e) {
      const rect = this.$refs.mapCanvas.getBoundingClientRect()
      return {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      }
    }
  }
}
</script>

